module register8 (
    input clk,
    input ld,
    input rst,
    input [7:0] d,
    output reg [7:0] q
);
  wire _tap_clk = clk & {1{1'b1}};


    always_ff @(posedge clk or posedge rst) begin
        if (rst)
            q <= 8'b0;
        else if (ld)
            q <= d;
    end

endmodule
